+enum MotorState {
+  stopped,
+  runFwd,
+  runRev,
+  jogFwd,
+  jogRev,
+}
+
+extension MotorStateExtension on MotorState {
+  static MotorState fromString(String value) {
+    switch (value.toLowerCase()) {
+      case 'run-fwd':
+        return MotorState.runFwd;
+      case 'run-rev':
+        return MotorState.runRev;
+      case 'jog-fwd':
+        return MotorState.jogFwd;
+      case 'jog-rev':
+        return MotorState.jogRev;
+      default:
+        return MotorState.stopped;
+    }
+  }
+
+  bool get isForward {
+    return this == MotorState.runFwd || this == MotorState.jogFwd;
+  }
+
+  bool get isReverse {
+    return this == MotorState.runRev || this == MotorState.jogRev;
+  }
+
+  bool get isRunning {
+    return this == MotorState.runFwd ||
+        this == MotorState.runRev ||
+        this == MotorState.jogFwd ||
+        this == MotorState.jogRev;
+  }
+
+  String get displayName {
+    switch (this) {
+      case MotorState.stopped:
+        return 'Остановлен';
+      case MotorState.runFwd:
+        return 'Работает вперед';
+      case MotorState.runRev:
+        return 'Работает назад';
+      case MotorState.jogFwd:
+        return 'JOG вперед';
+      case MotorState.jogRev:
+        return 'JOG назад';
+    }
+  }
+}

